const { PDFDocument, rgb, StandardFonts } = require('pdf-lib');

// ── Logo (PNG with transparency, black bg removed) embedded as base64 ─────────
const LOGO_BASE64 = '';

// ── Image URL resolver ────────────────────────────────────────────────────────
// Priority:
//   1. If item.imageUrl is a full URL → use it directly
//   2. If item.imageName is set → build Cloudinary URL from env vars
//   3. Neither → return null (show placeholder)
function resolveImageUrl(item) {
  if (item.imageUrl) return item.imageUrl;
  const cloudName = process.env.CLOUDINARY_CLOUD_NAME;
  if (cloudName && item.imageName) {
    // Strip any extension — Cloudinary public IDs don't include it
    const publicId = item.imageName.replace(/\.[^/.]+$/, '');
    // Use the folder prefix if set, otherwise images are at the root
    const folder = process.env.CLOUDINARY_FOLDER;
    const fullId = folder ? `${folder}/${publicId}` : publicId;
    // No version, no transformations — cleanest URL that always works
    const url = `https://res.cloudinary.com/${cloudName}/image/upload/${fullId}`;
    console.log(`[pdfService] Resolved image URL: ${url}`);
    return url;
  }
  console.warn(`[pdfService] Could not resolve image for item:`, item.imageName || '(no imageName)');
  return null;
}

// ── Image fetching ────────────────────────────────────────────────────────────
async function fetchImageData(url) {
  try {
    const res = await fetch(url);
    if (!res.ok) {
      console.error(`[pdfService] Image fetch failed: ${res.status} ${res.statusText} - ${url}`);
      return null;
    }
    const contentType = res.headers.get('content-type') || '';
    const buffer = Buffer.from(await res.arrayBuffer());
    console.log(`[pdfService] Fetched ${buffer.length} bytes, content-type: ${contentType} — ${url}`);
    return { buffer, contentType };
  } catch (err) {
    console.error(`[pdfService] Image fetch error: ${err.message} - ${url}`);
    return null;
  }
}

async function embedProductImage(pdfDoc, url) {
  if (!url) return null;
  const data = await fetchImageData(url);
  if (!data) return null;
  const { buffer, contentType } = data;

  // Use content-type from the actual HTTP response — never guess from the filename
  const isPng = contentType.includes('png');

  if (isPng) {
    try { return await pdfDoc.embedPng(buffer); } catch (e) {
      console.error(`[pdfService] embedPng failed: ${e.message}`);
    }
  } else {
    // jpeg / webp / anything else — try jpg first then png as fallback
    try { return await pdfDoc.embedJpg(buffer); } catch (_) {}
    try { return await pdfDoc.embedPng(buffer); } catch (e) {
      console.error(`[pdfService] embedPng fallback failed: ${e.message}`);
    }
  }
  console.error(`[pdfService] Could not embed image: ${url}`);
  return null;
}

// ── Drawing helpers ───────────────────────────────────────────────────────────
function hLine(page, x1, y, x2, color, thickness = 0.5) {
  page.drawLine({ start: { x: x1, y }, end: { x: x2, y }, thickness, color });
}

// ── Main export ───────────────────────────────────────────────────────────────
/**
 * @param {{
 *   clientName, clientCompany, clientEmail,
 *   clientAddress, clientPhone, createdAt,
 *   quotationNumber,
 *   quotationItems: Array<{
 *     productId, name, grammage, quantity,
 *     imageName?,   ← filename for Cloudinary
 *     imageUrl?     ← full URL (takes priority over imageName)
 *   }>
 * }} opts
 */
async function generateQuotationPDF({
  clientName, clientCompany, clientEmail,
  clientAddress, clientPhone, createdAt,
  quotationNumber, quotationItems,
}) {
  const pdfDoc = await PDFDocument.create();

  const fontReg  = await pdfDoc.embedFont(StandardFonts.Helvetica);
  const fontBold = await pdfDoc.embedFont(StandardFonts.HelveticaBold);

  const C = {
    red:    rgb(0.78, 0.08, 0.08),
    yellow: rgb(0.98, 0.82, 0.10),
    dark:   rgb(0.12, 0.12, 0.12),
    mid:    rgb(0.42, 0.42, 0.42),
    light:  rgb(0.98, 0.98, 0.98),
    stripe: rgb(0.995, 0.995, 0.995),
    border: rgb(0.83, 0.83, 0.83),
    white:  rgb(1, 1, 1),
  };

  const PW    = 595; const PH = 842;
  const M     = 45;  const INNER = PW - M * 2;
  const COL_IMG  = M;
  const COL_NAME = M + 70;
  const COL_GRAM = M + 330;
  const COL_QTY  = M + 430;
  const ROW_H    = 68;
  const IMG_SLOT = 56;

  // ── Embed logo (PNG with alpha) ───────────────────────────────────────────
  const logoBuf  = Buffer.from(LOGO_BASE64, 'base64');
  const logoImg  = await pdfDoc.embedPng(logoBuf);
  const logoDims = logoImg.scaleToFit(72, 64);

  // ── Pre-fetch unique product images ──────────────────────────────────────
  // Cache key = resolved URL so same image used for same product across grammages
  const urlCache = {}; // url -> embedded image | null
  const resolvedUrls = quotationItems.map(item => resolveImageUrl(item));

  const uniqueUrls = [...new Set(resolvedUrls.filter(Boolean))];
  await Promise.all(
    uniqueUrls.map(async (url) => {
      urlCache[url] = await embedProductImage(pdfDoc, url);
    })
  );

  // ── Page factory ──────────────────────────────────────────────────────────
  function newPage() {
    const p = pdfDoc.addPage([PW, PH]);
    p.drawRectangle({ x: 0, y: 0, width: PW, height: 8, color: C.yellow });
    hLine(p, M, 26, PW - M, C.border);
    p.drawText(
      'Cotizacion ' + quotationNumber + '  -  Documento generado automaticamente. Sujeto a confirmacion.',
      { x: M, y: 14, size: 6.5, font: fontReg, color: C.mid }
    );
    return p;
  }

  let page = newPage();
  let y    = PH - M;

  // ── HEADER ────────────────────────────────────────────────────────────────
  const HEADER_H = 80;
  page.drawRectangle({ x: 0, y: PH - HEADER_H, width: PW, height: HEADER_H, color: C.red });
  page.drawRectangle({ x: 0, y: PH - HEADER_H, width: PW, height: 5, color: C.yellow });

  // Logo — top right, no background box needed (PNG is transparent now)
  const LOGO_X = PW - M - logoDims.width;
  const LOGO_Y = PH - HEADER_H + (HEADER_H - logoDims.height) / 2 + 2;
  page.drawImage(logoImg, { x: LOGO_X, y: LOGO_Y, width: logoDims.width, height: logoDims.height });

  page.drawText('COTIZACION', { x: M, y: PH - 44, size: 26, font: fontBold, color: C.white });
  page.drawText('N: ' + quotationNumber, { x: M, y: PH - 64, size: 9, font: fontReg, color: rgb(1, 0.88, 0.88) });

  const displayDate = (() => {
    try {
      return new Date(createdAt + 'T12:00:00').toLocaleDateString('es-CO', {
        day: '2-digit', month: 'long', year: 'numeric',
      });
    } catch { return createdAt; }
  })();
  const dateW = fontReg.widthOfTextAtSize(displayDate, 9);
  page.drawText(displayDate, { x: LOGO_X - dateW - 12, y: PH - 44, size: 9, font: fontReg, color: C.white });

  y = PH - HEADER_H - 22;

  // ── CLIENT BLOCK ──────────────────────────────────────────────────────────
  const rightX = M + INNER / 2 + 10;
  page.drawText(clientName, { x: M, y, size: 14, font: fontBold, color: C.dark });
  y -= 16;
  page.drawText(clientCompany || '', { x: M, y, size: 10, font: fontReg, color: C.mid });
  y -= 18;
  page.drawText('Email:', { x: M, y, size: 8, font: fontBold, color: C.mid });
  page.drawText(clientEmail || '-', { x: M + 34, y, size: 9, font: fontReg, color: C.dark });
  page.drawText('Telefono:', { x: rightX, y, size: 8, font: fontBold, color: C.mid });
  page.drawText(clientPhone || '-', { x: rightX + 48, y, size: 9, font: fontReg, color: C.dark });
  y -= 13;
  page.drawText('Direccion:', { x: M, y, size: 8, font: fontBold, color: C.mid });
  page.drawText(clientAddress || '-', { x: M + 48, y, size: 9, font: fontReg, color: C.dark });
  y -= 22;

  hLine(page, M, y, PW - M, C.border);
  y -= 18;

  // ── TABLE HEADER ──────────────────────────────────────────────────────────
  page.drawRectangle({ x: M, y: y - 6, width: INNER, height: 22, color: C.yellow });
  page.drawText('Producto', { x: COL_NAME, y: y + 2, size: 8.5, font: fontBold, color: C.dark });
  page.drawText('Gramaje',  { x: COL_GRAM, y: y + 4, size: 8.5, font: fontBold, color: C.dark });
  page.drawText('Cantidad', { x: COL_QTY,  y: y + 2, size: 8.5, font: fontBold, color: C.dark });
  y -= 8;
  hLine(page, M, y, PW - M, C.red, 1.5);
  y -= 4;

  // ── PRODUCT ROWS ──────────────────────────────────────────────────────────
  for (let i = 0; i < quotationItems.length; i++) {
    const item   = quotationItems[i];
    const imgUrl = resolvedUrls[i];
    const img    = imgUrl ? (urlCache[imgUrl] || null) : null;

    if (y - ROW_H < 60) { page = newPage(); y = PH - M; }

    const rowBot = y - ROW_H;
    if (i % 2 === 0) {
      page.drawRectangle({ x: M, y: rowBot, width: INNER, height: ROW_H, color: C.stripe });
    }

    if (img) {
      const dims = img.scaleToFit(IMG_SLOT, IMG_SLOT);
      page.drawImage(img, {
        x: COL_IMG + (64 - dims.width)  / 2,
        y: rowBot  + (ROW_H - dims.height) / 2,
        width: dims.width, height: dims.height,
      });
    } else {
      // Branded placeholder
      page.drawRectangle({ x: COL_IMG + 2, y: rowBot + 8, width: 60, height: ROW_H - 16, color: rgb(0.98, 0.95, 0.80) });
      page.drawRectangle({ x: COL_IMG + 2, y: rowBot + 8, width: 60, height: 10, color: C.red });
      page.drawText('sin imagen', { x: COL_IMG + 9, y: rowBot + 11, size: 5.5, font: fontReg, color: C.white });
    }

    const nameText = item.name.length > 36 ? item.name.slice(0, 34) + '...' : item.name;
    const midY     = rowBot + ROW_H / 2;
    page.drawText(nameText, { x: COL_NAME, y: midY + 7,  size: 10, font: fontBold, color: C.dark });
    page.drawText('Ref. #' + item.productId, { x: COL_NAME, y: midY - 8, size: 7.5, font: fontReg, color: C.mid });
    page.drawText(item.grammage, { x: COL_GRAM, y: midY, size: 10, font: fontReg, color: C.dark });
    page.drawText(item.quantity + ' uds.', { x: COL_QTY, y: midY, size: 10, font: fontBold, color: C.red });

    hLine(page, M, rowBot, PW - M, C.border);
    y = rowBot;
  }

  // ── TOTALS ────────────────────────────────────────────────────────────────
  y -= 16;
  if (y < 90) { page = newPage(); y = PH - M; }

  const totalUnits = quotationItems.reduce((s, i) => s + Number(i.quantity), 0);
  page.drawRectangle({ x: M, y: y - 32, width: INNER, height: 40, color: C.light });
  page.drawRectangle({ x: M, y: y - 32, width: 4, height: 40, color: C.yellow });
  page.drawText('Total de referencias:', { x: M + 14, y: y - 10, size: 9.5, font: fontReg, color: C.dark });
  page.drawText(String(quotationItems.length), { x: COL_QTY, y: y - 10, size: 11, font: fontBold, color: C.red });
  page.drawText('Total de unidades:',    { x: M + 14, y: y - 24, size: 9.5, font: fontReg, color: C.dark });
  page.drawText(String(totalUnits),       { x: COL_QTY, y: y - 24, size: 11, font: fontBold, color: C.red });

  // ── NOTES ─────────────────────────────────────────────────────────────────
  y -= 58;
  if (y < 90) { page = newPage(); y = PH - M; }
  page.drawText('Notas:', { x: M, y, size: 9, font: fontBold, color: C.dark });
  y -= 13;
  const notes = [
    'Los precios no estan incluidos en este documento. Un asesor se comunicara con usted.',
    'Esta cotizacion tiene una vigencia de 15 dias habiles.',
    'Los gramajes y presentaciones estan sujetos a disponibilidad de inventario.',
  ];
  for (const note of notes) {
    page.drawText('- ' + note, { x: M, y, size: 8, font: fontReg, color: C.mid });
    y -= 12;
  }

  return Buffer.from(await pdfDoc.save());
}

module.exports = { generateQuotationPDF };